68	void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
69	{
70	    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
71	    if (!GI) return;
72	
73	    // 构建战斗结果
74	    FLFPBattleResult Result;
75	    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
76	    Result.bVictory = bVictory;
77	    Result.bEscaped = bEscaped;
78	
79	    if (bVictory)
80	    {
81	        Result.CapturedUnits = CapturedUnits;
82	        // 总奖励 = 基础奖励 + 击杀掉落
83	        Result.GoldReward = CachedBattleRequest.BaseGoldReward + AccumulatedDropGold;
84	        Result.FoodReward = CachedBattleRequest.BaseFoodReward + AccumulatedDropFood;
85	    }
86	    // 逃跑或失败：不给奖励（默认 0）
87	
88	    // 缓存结果，确认后写回
89	    CachedBattleResult = Result;
90	
91	    // 显示结算 UI
92	    if (BattleResultWidgetClass)
93	    {
94	        APlayerController* PC = GetWorld()->GetFirstPlayerController();
95	        if (PC)
96	        {
97	            BattleResultWidget = CreateWidget<ULFPBattleResultWidget>(PC, BattleResultWidgetClass);
98	            if (BattleResultWidget)
99	            {
100	                BattleResultWidget->Setup(Result, GI->UnitRegistry);
101	                BattleResultWidget->OnConfirmPressed.AddDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
102	                BattleResultWidget->AddToViewport(100);
103	
104	                // 切换到 UI 输入模式
105	                FInputModeUIOnly InputMode;
106	                InputMode.SetWidgetToFocus(BattleResultWidget->TakeWidget());
107	                PC->SetInputMode(InputMode);
108	                PC->SetShowMouseCursor(true);
109	            }
110	        }
111	    }
112	    else
113	    {
114	        // 无 Widget 类配置，直接返回（兼容测试场景）
115	        OnBattleResultConfirmed();
116	    }
117	}
118	
119	void ALFPTurnGameMode::OnBattleResultConfirmed()
120	{
121	    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
122	    if (!GI) return;
123	
124	    // 写回战斗结果
125	    GI->SetBattleResult(CachedBattleResult);
126	
127	    // 移除结算 UI
128	    if (BattleResultWidget)
129	    {
130	        BattleResultWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
131	        BattleResultWidget->RemoveFromParent();
132	        BattleResultWidget = nullptr;
133	    }
134	
135	    // 恢复输入模式
136	    if (APlayerController* PC = GetWorld()->GetFirstPlayerController())
137	    {
138	        FInputModeGameAndUI InputMode;
139	        PC->SetInputMode(InputMode);
140	    }
141	
142	    // 返回世界地图
143	    if (CachedBattleRequest.bIsValid)
144	    {
145	        GI->TransitionToWorldMap(TEXT(""));
146	    }
147	}
