149	void ALFPTurnGameMode::RecordCapturedUnit(ALFPTacticsUnit* Unit)
150	{
151	    if (!Unit) return;
152	
153	    FLFPUnitEntry Entry = Unit->ToUnitEntry();
154	    if (Entry.IsValid())
155	    {
156	        CapturedUnits.Add(Entry);
157	        UE_LOG(LogTemp, Log, TEXT("捕获单位: %s, 阶级 %d"), *Entry.TypeID.ToString(), Entry.Tier);
158	    }
159	}
