161	void ALFPTurnGameMode::OnEnemyUnitKilled(ALFPTacticsUnit* Unit)
162	{
163	    if (!Unit) return;
164	
165	    AccumulatedDropGold += Unit->DropGold;
166	    AccumulatedDropFood += Unit->DropFood;
167	    UE_LOG(LogTemp, Log, TEXT("敌方击杀掉落: 金币 +%d, 食物 +%d (累计: %d / %d)"),
168	        Unit->DropGold, Unit->DropFood, AccumulatedDropGold, AccumulatedDropFood);
169	}
