137	void ALFPTurnManager::SortUnitsBySpeed()
138	{
139	    // 按速度降序排序（速度高的先行动）
140	    // Todo: 速度相同时随机排序（玩家优先于AI）
141	    TurnOrderUnits.Sort([](const ALFPTacticsUnit& A, const ALFPTacticsUnit& B) {
142	        return A.GetSpeed() > B.GetSpeed();
143	        });
144	}
