148	void ALFPTurnManager::SetPhase(EBattlePhase NewPhase)
149	{
150	    CurrentPhase = NewPhase;
151	    UE_LOG(LogTemp, Log, TEXT("SetPhase:=%d"), NewPhase);
152	    OnPhaseChanged.Broadcast(NewPhase);
