311	// ==== 行动阶段 ====
312	
313	void ALFPTurnManager::BeginActionPhase()
314	{
315	    SetPhase(EBattlePhase::BP_ActionPhase);
316	
317	    // 开始第一个单位的回合
318	    if (TurnOrderUnits.Num() > 0)
319	    {
320	        BeginUnitTurn(TurnOrderUnits[0]);
321	    }
322	}
