324	void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
325	{
326	    if (bBattleEnded) return;
327	
328	    OnTurnChanged.Broadcast();
329	
330	    CurrentUnit = Unit;
331	
332	    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
333	
334	    // 敌方单位在行动阶段：执行预定计划
335	    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
336	    {
337	        if (PC)
338	        {
339	            PC->HideSkillSelection();
340	        }
341	
342	        Unit->OnTurnStarted();
343	
344	        ExecuteEnemyPlan(Unit);
345	        return;
346	    }
347	
348	    // 玩家单位：保持原有逻辑
349	    if (Unit)
350	    {
351	        Unit->OnTurnStarted();
352	    }
353	
354	    if (PC)
355	    {
356	        PC->OnTurnStarted(Unit);
357	        PC->SelectUnit(Unit);
358	        PC->HandleSkillSelection();
359	    }
360	}
361	
362	void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
363	{
364	    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
365	
366	    if (Plan.bIsValid && Plan.PlannedSkill)
367	    {
368	        // 在原定目标格子释放技能（即使目标已死亡）
369	        // AP 已在规划阶段 AllocateEnemySkills 中扣除
370	        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
371	    }
372	
373	    // 清除头顶技能图标
374	    Unit->ClearActionPlan();
375	
376	    // 短延时后结束回合（让玩家看到技能效果）
377	    FTimerHandle TimerHandle;
378	    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
379	    {
380	        Unit->SetHasActed(true);
381	        PassTurn();
382	    }, 0.5f, false);
383	}
384	
385	void ALFPTurnManager::EndUnitTurn(ALFPTacticsUnit* Unit)
386	{
387	    if (Unit)
388	    {
389	        Unit->OnTurnEnded();
390	    }
391	
392	    // 通知玩家控制器
393	    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
394	    {
395	        PC->OnTurnEnded(Unit);
396	    }
397	}
398	
399	void ALFPTurnManager::PassTurn()
400	{
401	    if (bBattleEnded) return;
402	
403	    if (TurnOrderUnits.IsEmpty())
404	    {
405	        return;
406	    }
407	
408	    // 结束当前单位回合
409	    if (CurrentUnit)
410	    {
411	        EndUnitTurn(CurrentUnit);
412	    }
413	
414	    // 找到下一个未行动的单位
415	    int32 CurrentIndex = CurrentUnit ? TurnOrderUnits.Find(CurrentUnit) : -1;
416	    int32 StartIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
417	
418	    // 检查所有单位是否行动完毕
419	    bool TurnOrderUnitsActed = true;
420	    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
421	    {
422	        if (Unit && Unit->IsAlive() && !Unit->HasActed())
423	        {
424	            TurnOrderUnitsActed = false;
425	            break;
426	        }
427	    }
428	
429	    if (TurnOrderUnitsActed)
430	    {
431	        // 所有单位行动完毕，结束回合
432	        EndCurrentRound();
433	    }
434	    else
435	    {
436	        // 寻找下一个未行动单位
437	        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
438	        {
439	            int32 Index = (StartIndex + i) % TurnOrderUnits.Num();
440	            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
441	
442	            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
443	            {
444	                BeginUnitTurn(NextUnit);
445	                return;
446	            }
447	        }
448	
449	        // 没有找到未行动单位，结束回合
450	        EndCurrentRound();
451	    }
452	}
453	
454	void ALFPTurnManager::OnUnitFinishedAction(ALFPTacticsUnit* Unit)
455	{
456	    if (Unit == CurrentUnit)
457	    {
458	        Unit->SetHasActed(true);
459	
460	        // 自动传递回合
461	        PassTurn();
462	    }
463	}
