465	void ALFPTurnManager::RegisterUnit(ALFPTacticsUnit* Unit)
466	{
467	    if (Unit && !TurnOrderUnits.Contains(Unit))
468	    {
469	        TurnOrderUnits.Add(Unit);
470	
471	        // 如果游戏已经开始，重新排序
472	        if (bIsInRound)
473	        {
474	            SortUnitsBySpeed();
475	        }
476	    }
477	}
478	
479	void ALFPTurnManager::UnregisterUnit(ALFPTacticsUnit* Unit)
480	{
481	    if (Unit)
482	    {
483	        bool bWasCurrentUnit = (Unit == CurrentUnit);
484	        TurnOrderUnits.Remove(Unit);
485	
486	        // 先检查战斗结束条件
487	        CheckBattleEnd();
488	
489	        // 如果战斗未结束且当前单位被移除，传递回合
490	        if (!bBattleEnded && bWasCurrentUnit)
491	        {
492	            PassTurn();
493	        }
494	    }
495	}
