587	void ALFPTurnManager::CheckBattleEnd()
588	{
589	    if (bBattleEnded) return;
590	    if (CurrentPhase == EBattlePhase::BP_Deployment) return;
591	
592	    bool bHasPlayerUnit = false;
593	    bool bHasEnemyUnit = false;
594	
595	    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
596	    {
597	        if (!Unit || !Unit->IsAlive()) continue;
598	
599	        if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player)
600	            bHasPlayerUnit = true;
601	        else if (Unit->GetAffiliation() == EUnitAffiliation::UA_Enemy)
602	            bHasEnemyUnit = true;
603	    }
604	
605	    if (!bHasEnemyUnit)
606	    {
607	        // 胜利：所有敌方单位消灭
608	        bBattleEnded = true;
609	        UE_LOG(LogTemp, Log, TEXT("战斗结束: 胜利！"));
610	        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
611	        {
612	            GM->EndBattle(true);
613	        }
614	    }
615	    else if (!bHasPlayerUnit)
616	    {
617	        // 失败：所有玩家单位消灭
618	        bBattleEnded = true;
619	        UE_LOG(LogTemp, Log, TEXT("战斗结束: 败北"));
620	        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
621	        {
622	            GM->EndBattle(false);
623	        }
624	    }
625	}
