139	void ALFPTacticsUnit::AddCurrentMaxHealth(int32 Delta, bool bKeepHealthRatio)
140	{
141	    const int32 OldMaxHealth = CurrentMaxHealth;
142	    CurrentMaxHealth = FMath::Max(1, CurrentMaxHealth + Delta);
143	    MaxHealth = CurrentMaxHealth;
144	
145	    if (bKeepHealthRatio && OldMaxHealth > 0)
146	    {
147	        const float HealthRatio = static_cast<float>(CurrentHealth) / OldMaxHealth;
148	        CurrentHealth = FMath::Clamp(FMath::RoundToInt(CurrentMaxHealth * HealthRatio), 0, CurrentMaxHealth);
149	    }
150	    else
151	    {
152	        CurrentHealth = FMath::Clamp(CurrentHealth + Delta, 0, CurrentMaxHealth);
153	    }
154	    OnHealthChangedDelegate.Broadcast(CurrentHealth, CurrentMaxHealth);
155	}
