169	void ALFPTacticsUnit::BeginPlay()
170	{
171	    Super::BeginPlay();
172	
173	    if (!bStatsInitialized)
174	    {
175	        if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
176	        {
177	            InitializeFromRegistry(GI->UnitRegistry);
178	        }
179	        else
180	        {
181	            ResetCurrentStatsToBase();
182	        }
183	    }
184	
185	    // 注册到回合管理器
186	    if (ALFPTurnManager* TurnManager = GetTurnManager())
187	    {
188	        TurnManager->RegisterUnit(this);
189	    }
190	
191	    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
192	    {
193	        if (Condition)
194	        {
195	            Condition->RegisterCondition(this);
196	        }
197	    }
198	
199	    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
200	    SetCurrentCoordinates(SpawnPoint);
201	
202		// 初始化血量
203	    CurrentHealth = FMath::Clamp(CurrentHealth, 0, GetCurrentMaxHealth());
204		InitializeHealthBar();
205	
206	    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
207	
208	    // 如果是敌方单位，创建AI控制器
209	    if (IsEnemy())
210	    {
211	        FActorSpawnParameters SpawnParams;
212	        SpawnParams.Owner = this;
213	        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
214	
215	        if (AIControllerClass)
216	        {
217	            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
218	            if (AIController)
219	            {
220	                AIController->Possess(this);
221	                AIController->SetControlledUnit(this);
222	            }
223	        }
224	    }
225	}
