305	bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
306	{
307	    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
308	
309	    ALFPHexGridManager* GridManager = GetGridManager();
310	    if (!GridManager) return false;
311	
312	    // 获取当前所在的格子
313	    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
314	    if (!CurrentTile) return false;
315	
316	    // 寻找路径（FindPath 返回的路径不包含起点）
317	    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
318	    // 计算路径实际移动代价（考虑地形）
319	    int32 PathCost = 0;
320	    for (ALFPHexTile* Tile : MovePath)
321	    {
322	        PathCost += Tile->GetMovementCost();
323	    }
324	    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
325	
326	    // 在路径开头插入当前格子，使 Tick 中 MovePath[0] → MovePath[1] 为第一段移动
327	    MovePath.Insert(CurrentTile, 0);
328	
329	    // 设置移动状态
330	    CurrentTile->SetIsOccupied(false);
331	    TargetTile = NewTargetTile;
332	    CurrentPathIndex = 0;
333	    MoveProgress = 0.0f;
334	    MovementRangeTiles.Empty();
335	
336	    // 启动移动动画（Tick 驱动逐格插值）
337	    bIsMoving = true;
338	
339	    return true;
340	}
