347	void ALFPTacticsUnit::FinishMove()
348	{
349	    bIsMoving = false;
350	
351	    // 更新到目标位置
352	    if (TargetTile)
353	    {
354	        SetCurrentCoordinates(TargetTile->GetCoordinates());
355	        // 计算路径实际移动代价（跳过 MovePath[0] 即起点格子）
356	        int32 TotalCost = 0;
357	        for (int32 i = 1; i < MovePath.Num(); i++)
358	        {
359	            TotalCost += MovePath[i]->GetMovementCost();
360	        }
361	        ConsumeMovePoints(TotalCost);
362	    }
363	
364	    // 清除移动状态
365	    TargetTile = nullptr;
366	    MovePath.Empty();
367	    CurrentPathIndex = -1;
368	    MoveProgress = 0.0f;
369	
370	    // 广播移动完成
371	    OnMoveFinished.Broadcast();
372	}
