512	    Super::Tick(DeltaTime);
513	
514	    // 逐格平滑移动
515	    if (bIsMoving && CurrentPathIndex >= 0 && CurrentPathIndex < MovePath.Num() - 1)
516	    {
517	        MoveProgress += MoveSpeed * DeltaTime;
518	
519	        ALFPHexTile* FromTile = MovePath[CurrentPathIndex];
520	        ALFPHexTile* ToTile = MovePath[CurrentPathIndex + 1];
521	
522	        if (FromTile && ToTile)
523	        {
524	            FVector StartPos = FromTile->GetActorLocation() + FVector(0, 0, 1);
525	            FVector EndPos = ToTile->GetActorLocation() + FVector(0, 0, 1);
526	
527	            float Alpha = FMath::Clamp(MoveProgress, 0.f, 1.f);
528	            SetActorLocation(FMath::Lerp(StartPos, EndPos, Alpha));
529	        }
530	
531	        if (MoveProgress >= 1.0f)
532	        {
533	            CurrentPathIndex++;
534	            MoveProgress = 0.0f;
535	
536	            if (CurrentPathIndex >= MovePath.Num() - 1)
537	            {
538	                // 到达终点
539	                FinishMove();
540	            }
541	        }
542	    }
543	}
