559	void ALFPTacticsUnit::TakeDamage(int32 Damage)
560	{
561	    if (bIsDead) return;
562	
563		// 计算实际伤害（考虑防御）
564		int32 ActualDamage = FMath::Max(Damage - GetPhysicalBlock(), 1);
565		CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
566	
567		// 广播血量变化事件
568		OnHealthChangedDelegate.Broadcast(CurrentHealth, GetCurrentMaxHealth());
569	
570		// 蓝图事件
571		OnTakeDamage(ActualDamage);
572	
573		// 检查死亡
574		if (CurrentHealth <= 0)
575		{
576			HandleDeath();
577		}
578	}
