716	ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
717	{
718	    // 获取所有玩家单位
719	    TArray<AActor*> PlayerUnits;
720	    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
721	
722	    ALFPTacticsUnit* BestTarget = nullptr;
723	    float BestThreatValue = -MAX_FLT;
724	
725	    for (AActor* Actor : PlayerUnits)
726	    {
727	        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
728	        if (Unit && Unit->IsAlive() && Unit->IsAlly())
729	        {
