855	TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
856	{
857	    TArray<ALFPHexTile*> AttackRangeTiles;
858	
859	    if (ALFPHexGridManager* GridManager = GetGridManager())
860	    {
861	        // 近战攻击范围
862	        if (bMeleeAttack)
863	        {
864	            // 获取相邻格子
865	            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
866	            for (const FLFPHexCoordinates& Coord : Neighbors)
867	            {
868	                FLFPHexCoordinates Key(Coord.Q, Coord.R);
869	                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
870	                {
871	                    AttackRangeTiles.Add(Tile);
872	                }
873	            }
874	        }
875	        // 远程攻击范围
876	        else
877	        {
878	            // 获取攻击范围内的所有格子
879	            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
880	
881	            for (ALFPHexTile* Tile : TilesInRange)
882	            {
883	                AttackRangeTiles.Add(Tile);
884	            }
885	        }
886	    }
887	
888	    return AttackRangeTiles;
889	}
