891	bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
892	{
893	    if (!Target || !Target->GetCurrentTile()) return false;
894	
895	    // 计算距离
896	    int32 Distance = FLFPHexCoordinates::Distance(
897	        CurrentCoordinates,
898	        Target->GetCurrentCoordinates()
899	    );
900	
901	    // 近战攻击判定
902	    if (bMeleeAttack)
903	    {
904	        return Distance == 1; // 相邻格子
905	    }
906	    // 远程攻击判定
907	    else
908	    {
909	        return Distance >= 2 && Distance <= AttackRange;
910	    }
911	}
