782	void ALFPTacticsPlayerController::SkipTurn(ALFPTacticsUnit* Unit)
783	{
784	    if (!Unit || !Unit->CanAct()) return;
785	
786	    // 标记为已行动
787	    Unit->SetHasActed(true);
788	
789	    // 可选：消耗1个行动力作为跳过代价
790	    // Unit->ConsumeMovePoints(1);
791	    bIsAttacking = false;
792	    CurrentControlState = EPlayControlState::MoveState;
793	    // 通知回合管理器单位完成行动
794	    if (ALFPTurnManager* TurnManager = GetTurnManager())
795	    {
796	        TurnManager->OnUnitFinishedAction(Unit);
797	    }
798	}
