800	void ALFPTacticsPlayerController::ExecuteSkill(ULFPSkillBase* CurrentSkill)
801	{
802	    if (SelectedUnit && SelectedTile && CurrentSkill)
803	    {
804	        if (CurrentSkill->CanExecute(SelectedTile))
805	        {
806	            bIsReleaseSkill = false;
807	            CurrentSkill->Execute(SelectedTile);
808	            SelectedUnit->ConsumeActionPoints(CurrentSkill->ActionPointCost);
809	            CurrentControlState = EPlayControlState::MoveState;
810	            ShowUnitRange(EUnitRange::UR_Move);
811	            SkipTurn(SelectedUnit);
812	        }
813	        else
814	        {
815	            UE_LOG(LogTemp, Log, TEXT("Skill:%s can not release!"), *CurrentSkill->SkillName.ToString());
816	        }
817	    }
818	}
